import{_ as i,c as r,o,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.3: Bedrock Enhancements + Desktop CLI Installation","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.3.md","filePath":"en/changelog/v1.1.3.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.3.md"};function s(l,a,d,h,c,p){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-3-bedrock-enhancements-desktop-cli-installation" tabindex="-1">v1.1.3: Bedrock Enhancements + Desktop CLI Installation <a class="header-anchor" href="#v1-1-3-bedrock-enhancements-desktop-cli-installation" aria-label="Permalink to “v1.1.3: Bedrock Enhancements + Desktop CLI Installation”">​</a></h1><p><strong>Release Date</strong>: January 5, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update enhances <strong>Amazon Bedrock support</strong>, allows <strong>one-click CLI installation</strong> in the desktop app, and fixes multiple stability issues.</p><hr><h2 id="new-feature-enhanced-bedrock-configuration" tabindex="-1">New Feature: Enhanced Bedrock Configuration <a class="header-anchor" href="#new-feature-enhanced-bedrock-configuration" aria-label="Permalink to “New Feature: Enhanced Bedrock Configuration”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Amazon Bedrock users now have more configuration options:</p><ul><li>Support for <strong>jp. prefix</strong> cross-region inference configuration</li><li>Clearer <strong>authentication priority</strong></li><li>More flexible configuration options</li></ul><h3 id="authentication-priority" tabindex="-1">Authentication Priority <a class="header-anchor" href="#authentication-priority" aria-label="Permalink to “Authentication Priority”">​</a></h3><ol><li>API Key in configuration file</li><li>Environment variables</li><li>AWS CLI configuration</li><li>IAM role</li></ol><p>👉 <strong>Related Tutorial</strong>: <a href="/en/appendix/providers.html">Model Providers</a></p><hr><h2 id="desktop-app-one-click-cli-installation" tabindex="-1">Desktop App: One-Click CLI Installation <a class="header-anchor" href="#desktop-app-one-click-cli-installation" aria-label="Permalink to “Desktop App: One-Click CLI Installation”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>The desktop app can now <strong>install the CLI tool with one click</strong>, no separate download required.</p><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3><ol><li>Open desktop app settings</li><li>Find the &quot;Install CLI&quot; option</li><li>Click to install</li></ol><p>After installation, you can use the <code>opencode</code> command in your terminal.</p><hr><h2 id="improvement-permission-configuration-order-preserved" tabindex="-1">Improvement: Permission Configuration Order Preserved <a class="header-anchor" href="#improvement-permission-configuration-order-preserved" aria-label="Permalink to “Improvement: Permission Configuration Order Preserved”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When configuring permission rules, the order might be scrambled, causing unexpected priority behavior.</p><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to “Current Behavior”">​</a></h3><p>Now <strong>preserves your defined order</strong>, with the first rule having the highest priority.</p><hr><h2 id="improvement-custom-commands-support-images" tabindex="-1">Improvement: Custom Commands Support Images <a class="header-anchor" href="#improvement-custom-commands-support-images" aria-label="Permalink to “Improvement: Custom Commands Support Images”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>When using custom commands, image parameters could not be passed.</p><h3 id="current-behavior-1" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-1" aria-label="Permalink to “Current Behavior”">​</a></h3><p>You can now use images in custom commands, such as screenshot analysis and image processing scenarios.</p><hr><h2 id="improvement-tab-expands-directories" tabindex="-1">Improvement: Tab Expands Directories <a class="header-anchor" href="#improvement-tab-expands-directories" aria-label="Permalink to “Improvement: Tab Expands Directories”">​</a></h2><h3 id="previous-issue-2" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-2" aria-label="Permalink to “Previous Issue”">​</a></h3><p>In file autocomplete, the behavior of Tab and Enter was not intuitive enough.</p><h3 id="current-behavior-2" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior-2" aria-label="Permalink to “Current Behavior”">​</a></h3><ul><li><strong>Tab</strong>: Expand directory to view sub-files</li><li><strong>Enter</strong>: Select current item</li></ul><p>More intuitive operation.</p><hr><h2 id="desktop-app-improvements" tabindex="-1">Desktop App Improvements <a class="header-anchor" href="#desktop-app-improvements" aria-label="Permalink to “Desktop App Improvements”">​</a></h2><table tabindex="0"><thead><tr><th>Improvement</th><th>Description</th></tr></thead><tbody><tr><td>Image attachment storage</td><td>Images are now correctly saved</td></tr><tr><td>Bottom padding fix</td><td>Content no longer obscured</td></tr><tr><td>Terminal stability</td><td>Fixed terminal flickering issue</td></tr><tr><td>Event batching</td><td>Improved overall performance</td></tr><tr><td>Input box no longer obscures content</td><td>Smoother scrolling in long conversations</td></tr><tr><td>Worktree navigation fix</td><td>Correct redirect after selecting worktree</td></tr><tr><td>IME input fix</td><td>Chinese input method no longer triggers submit incorrectly</td></tr><tr><td>Project collapse highlight</td><td>Collapsed active project is highlighted</td></tr></tbody></table><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using Amazon Bedrock</td><td>✅ Upgrade</td></tr><tr><td>Using desktop app</td><td>✅ Upgrade</td></tr><tr><td>Using Chinese input method</td><td>✅ Upgrade, IME issue fixed</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',46),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Fix terminal long-running processes</li><li>Preserve permission configuration key order, maintaining user-defined priority</li><li>Custom commands support passing images (@melihmucuk)</li><li>Support jp. prefix for Amazon Bedrock cross-region inference (@ikeda-tomoya-swx)</li><li>Bedrock configuration options and authentication priority (@wnkz)</li><li>Transform agent improvements and optimizations</li><li>Filter empty messages and reasoning for Anthropic API compatibility</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Tab expands directories, Enter selects (@yuguorui)</li><li>Update GitHub Actions example to use actions/checkout@v6 (@joshuadavidthomas)</li><li>Fix Lucent Orange theme slash command background transparency (@roerohan)</li><li>Add MCP command documentation (@cravenceiling)</li><li>Add system theme parsing and event handling</li><li>Improve experience when operation is interrupted</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Store image attachments</li><li>Fix bottom padding</li><li>Fix terminal flickering issue</li><li>Event batching for performance improvement</li><li>Fix input box obscuring content</li><li>Correct navigation after worktree selection</li><li>Avoid incorrect submit during IME input (@MogamiTsuchikawa)</li><li>Highlight collapsed active project (@albingroen)</li><li>Fix flickering and navigation issues when collapsing/expanding projects (@albingroen)</li><li>Add CLI installation feature (@dbpolito)</li><li>Fix image drag in project edit dialog (@albingroen)</li></ul><h3 id="community-contributors" tabindex="-1">Community Contributors <a class="header-anchor" href="#community-contributors" aria-label="Permalink to “Community Contributors”">​</a></h3><p>Thanks to 10 community contributors!</p></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=i(n,[["render",s]]);export{u as __pageData,g as default};
